import React, { useState, useContext } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import './Auth.css';

const Register = () => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    password: '',
    role: 'worker',
    location: {
      address: '',
      city: '',
      district: '',
      state: '',
      pincode: ''
    },
    skills: [],
    experience: { years: 0 }
  });
  const [profileFile, setProfileFile] = useState(null);
  const [error, setError] = useState('');
  const { register } = useContext(AuthContext);
  const navigate = useNavigate();

  const skillOptions = ['painter', 'electrician', 'mason', 'helper', 'plumber', 'carpenter', 'welder', 'cleaner', 'gardener', 'loader', 'fabricator', 'tiler'];

  const handleChange = (e) => {
    const { name, value } = e.target;
    if (name.startsWith('location.')) {
      const field = name.split('.')[1];
      setFormData({ ...formData, location: { ...formData.location, [field]: value } });
    } else {
      setFormData({ ...formData, [name]: value });
    }
  };

  const handleSkillToggle = (skill) => {
    const skills = formData.skills.includes(skill)
      ? formData.skills.filter(s => s !== skill)
      : [...formData.skills, skill];
    setFormData({ ...formData, skills });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    console.log('Submitting registration, role:', formData.role, 'step:', step);
    console.log('Form data:', formData);
    
    if (formData.role === 'worker' && step === 1) {
      if (formData.password.length < 6) {
        setError('Password must be at least 6 characters');
        return;
      }
      setStep(2);
      return;
    }
    setError('');

    let result;
    // If there's a profile photo, use FormData (multipart/form-data)
    if (profileFile) {
      const data = new FormData();
      data.append('name', formData.name);
      data.append('email', formData.email);
      data.append('phone', formData.phone);
      data.append('password', formData.password);
      data.append('role', formData.role);
      data.append('location', JSON.stringify(formData.location));

      if (formData.role === 'worker') {
        data.append('skills', JSON.stringify(formData.skills));
        data.append('experience', JSON.stringify(formData.experience));
      }

      data.append('profileImage', profileFile);
      result = await register(data);
    } else {
      // If no photo, send as regular JSON
      result = await register(formData);
    }

    if (result.success) {
      if (result.user.role === 'worker') {
        navigate('/worker/dashboard');
      } else {
        navigate('/employer/dashboard');
      }
    } else {
      setError(result.message);
    }
  };

  return (
    <div className="auth-container">
      <div className="auth-card">
        <h2>{step === 1 ? 'Join SkillConnect' : 'Complete Your Profile'}</h2>
        {error && <div className="error-message">{error}</div>}
        <form onSubmit={handleSubmit}>
          {step === 1 ? (
            <>
              <div className="form-group">
                <label>Full Name</label>
                <input
                  type="text"
                  name="name"
                  value={formData.name}
                  onChange={handleChange}
                  required
                />
              </div>
              <div className="form-group">
                <label>Email Address</label>
                <input
                  type="email"
                  name="email"
                  value={formData.email}
                  onChange={handleChange}
                  required
                />
              </div>
              <div className="form-group">
                <label>Phone Number</label>
                <input
                  type="text"
                  name="phone"
                  value={formData.phone}
                  onChange={handleChange}
                  required
                />
              </div>
              <div className="form-group">
                <label>Password</label>
                <input
                  type="password"
                  name="password"
                  value={formData.password}
                  onChange={handleChange}
                  required
                />
              </div>

              <div className="form-group">
                <label>I am a:</label>
                <select name="role" value={formData.role} onChange={handleChange}>
                  <option value="worker">Worker / Skilled Laborer</option>
                  <option value="employer">Employer / Home Owner</option>
                </select>
              </div>
              
              <button type="submit" className="auth-btn">
                {formData.role === 'worker' ? 'Next' : 'Register'}
              </button>
            </>
          ) : (
            <>
              <div className="form-group">
                <label>Profile Photo</label>
                <input
                  type="file"
                  accept="image/*"
                  onChange={(e) => setProfileFile(e.target.files[0])}
                />
              </div>

              <div className="form-group">
                <label>Select Your Skills (Select multiple)</label>
                <div className="skills-grid">
                  {skillOptions.map(skill => (
                    <label key={skill} className="skill-checkbox">
                      <input
                        type="checkbox"
                        checked={formData.skills.includes(skill)}
                        onChange={() => handleSkillToggle(skill)}
                      />
                      <span>{skill}</span>
                    </label>
                  ))}
                </div>
              </div>

              <div className="form-group">
                <label>Years of Experience</label>
                <input
                  type="number"
                  name="experience.years"
                  value={formData.experience.years}
                  onChange={(e) => setFormData({...formData, experience: { years: parseInt(e.target.value) || 0 }})}
                  min="0"
                />
              </div>

              <div className="form-group">
                <label>Address</label>
                <input
                  type="text"
                  name="location.address"
                  value={formData.location.address}
                  onChange={handleChange}
                  placeholder="Street address"
                  required
                />
              </div>

              <div className="form-group">
                <label>City</label>
                <input
                  type="text"
                  name="location.city"
                  value={formData.location.city}
                  onChange={handleChange}
                  required
                />
              </div>

              <div className="form-group">
                <label>District</label>
                <input
                  type="text"
                  name="location.district"
                  value={formData.location.district}
                  onChange={handleChange}
                  required
                />
              </div>

              <div className="form-group">
                <label>State</label>
                <input
                  type="text"
                  name="location.state"
                  value={formData.location.state}
                  onChange={handleChange}
                  required
                />
              </div>

              <div className="form-group">
                <label>Pincode</label>
                <input
                  type="text"
                  name="location.pincode"
                  value={formData.location.pincode}
                  onChange={handleChange}
                  required
                />
              </div>

              <div className="form-actions">
                <button type="button" className="back-btn" onClick={() => setStep(1)}>Back</button>
                <button type="submit" className="auth-btn">Complete Registration</button>
              </div>
              {error && <div className="error-message" style={{ marginTop: '15px' }}>{error}</div>}
            </>
          )}
        </form>
        {step === 1 && (
          <p>
            Already have an account? <Link to="/login">Login here</Link>
          </p>
        )}
      </div>
    </div>
  );
};

export default Register;
